+  <div class="world-scene" :class="themeClass">
+    <div class="lighting-overlay"></div>
+    <div class="windows">
+      <div v-for="(window, index) in windows" :key="index" class="window">
+        <div v-if="isNight" class="stars"></div>
+        <div v-else class="window-light"></div>
+      </div>
+    </div>
+    <div class="torches" v-if="isNight">
+      <div v-for="(torch, index) in torches" :key="index" class="torch"></div>
+    </div>
+    <!-- existing content -->
+  </div>
 </template>

 <script setup>
-import { ref } from 'vue'
+import { ref, computed, onMounted, onUnmounted } from 'vue'
+
+const cycleDuration = 5 * 60 * 1000 // 5 minutes in ms
+const windows = ref(new Array(5).fill(null))
+const torches = ref(new Array(3).fill(null))
+
+const startTime = Date.now()
+const time = ref(0)
+
+let timerId = null
+
+function updateTime() {
+  time.value = (Date.now() - startTime) % cycleDuration
+}
+
+onMounted(() => {
+  updateTime()
+  timerId = setInterval(updateTime, 1000)
+})
+
+onUnmounted(() => {
+  clearInterval(timerId)
+})
+
+const isNight = computed(() => {
+  // Night is second half of cycle (2.5 to 5 min)
+  return time.value >= cycleDuration / 2
+})
+
+const themeClass = computed(() => (isNight.value ? 'night' : 'day'))
 </script>

 <style scoped>
+.world-scene {
+  position: relative;
+  width: 100%;
+  height: 100%;
+  transition: background-color 1s ease;
+}
+
+.world-scene.day {
+  background-color: #f0e6d2; /* warm day color */
+}
+
+.world-scene.night {
+  background-color: #0b1a3d; /* dark blue night */
+}
+
+.lighting-overlay {
+  position: absolute;
+  top: 0; left: 0; right: 0; bottom: 0;
+  pointer-events: none;
+  transition: background-color 1s ease;
+}
+
+.world-scene.day .lighting-overlay {
+  background: rgba(255, 200, 100, 0.15);
+}
+
+.world-scene.night .lighting-overlay {
+  background: rgba(20, 40, 80, 0.5);
+}
+
+.windows {
+  position: relative;
+  display: flex;
+  gap: 10px;
+  padding: 10px;
+}
+
+.window {
+  width: 40px;
+  height: 60px;
+  background: #333;
+  border: 2px solid #555;
+  position: relative;
+  overflow: hidden;
+  border-radius: 4px;
+}
+
+.window-light {
+  position: absolute;
+  top: 10px; left: 10px; right: 10px; bottom: 10px;
+  background: radial-gradient(circle at center, #ffd966 60%, transparent 80%);
+  opacity: 0.8;
+  border-radius: 2px;
+}
+
+.stars {
+  position: absolute;
+  top: 5px; left: 5px; right: 5px; bottom: 5px;
+  background: transparent;
+}
+
+.stars::before, .stars::after {
+  content: '';
+  position: absolute;
+  background: white;
+  border-radius: 50%;
+  opacity: 0.8;
+}
+
+.stars::before {
+  width: 4px; height: 4px;
+  top: 10px; left: 15px;
+  box-shadow:
+    10px 5px white,
+    20px 15px white,
+    30px 10px white;
+}
+
+.stars::after {
+  width: 2px; height: 2px;
+  top: 25px; left: 5px;
+  box-shadow:
+    15px 20px white,
+    25px 25px white,
+    35px 15px white;
+}
+
+.torches {
+  position: absolute;
+  bottom: 20px;
+  left: 20px;
+  display: flex;
+  gap: 15px;
+}
+
+.torch {
+  width: 20px;
+  height: 40px;
+  background: linear-gradient(to top, #552200, #aa6600);
+  border-radius: 5px 5px 0 0;
+  position: relative;
+  box-shadow: 0 0 10px 3px rgba(255, 140, 0, 0.7);
+}
+
+.torch::after {
+  content: '';
+  position: absolute;
+  top: -15px;
+  left: 50%;
+  transform: translateX(-50%);
+  width: 12px;
+  height: 20px;
+  background: radial-gradient(circle at center, #ffb347 40%, transparent 70%);
+  filter: drop-shadow(0 0 6px #ffb347);
+  border-radius: 50% 50% 50% 50% / 60% 60% 40% 40%;
+  animation: flicker 1.5s infinite alternate;
+}
+
+@keyframes flicker {
+  0% { opacity: 0.8; transform: translateX(-50%) scale(1); }
+  100% { opacity: 1; transform: translateX(-48%) scale(1.05); }
+}
 </style>
